      const bm169RootFormInputs = bm169Object(target['formInputs']);
      const bm169NestedFormInputs = bm169Object(
        bm169RootFormInputs['formInputs'],
      );
      const bm169FormInputs =
        Object.keys(bm169NestedFormInputs).length > 0
