      const firstText = (...values: unknown[]): string => {
        for (const value of values) {
          const normalized = text(value);
          if (
            normalized.length > 0 &&
            normalized.toLowerCase() !== 'null' &&
            normalized.toLowerCase() !== 'undefined'
          ) {
            return normalized;
          }
        }
        return '';
      };

      const boolFlag = (value: unknown): boolean => {
        if (value === true) return true;
        const raw = text(value).toLowerCase();
        return raw === 'true' || raw === '1' || raw === 'yes' || raw === 'on';
      };

      const hasOwn = (obj: any, key: string): boolean =>
        obj &&
        typeof obj === 'object' &&
        Object.prototype.hasOwnProperty.call(obj, key);

      const stripListLine = (value: unknown): string =>
        text(value)
          .replace(/^-+\s*/u, '')
          .replace(/[;.\s]+$/u, '')
          .trim();

      const ensureEnd = (value: string, ending: string): string => {
        const raw = text(value)
          .replace(/\s+([,.;:])/gu, '$1')
          .replace(/\s{2,}/gu, ' ');
        if (!raw) return '';
        return /[.!?;,]$/u.test(raw)
          ? raw.replace(/[.!?;,]$/u, ending)
          : `${raw}${ending}`;
      };

      const normalizeAgencyBodyName = (value: unknown): string => {
        const raw = text(value);
        if (!raw) return 'viện kiểm sát nhân dân khu vực 7';

        const upper = raw
          .toLocaleUpperCase('vi-VN')
          .replace(/\s+/g, ' ')
          .trim();

        if (upper === 'VIỆN KIỂM SÁT NHÂN DÂN KHU VỰC 7') {
          return 'viện kiểm sát nhân dân khu vực 7';
        }

        if (upper === 'VIỆN KIỂM SÁT NHÂN DÂN THÀNH PHỐ HỒ CHÍ MINH') {
          return 'viện kiểm sát nhân dân Thành phố Hồ Chí Minh';
        }

        return raw
          .replace(/^Viện kiểm sát/u, 'viện kiểm sát')
          .replace(/^VIỆN KIỂM SÁT/u, 'viện kiểm sát');
      };

      const formatDateForLine = (value: unknown): string => {
        const raw = text(value);
        if (!raw) return '';

        if (/ngày\s+\d{1,2}\s+tháng\s+\d{1,2}\s+năm\s+\d{4}/iu.test(raw)) {
          return raw
            .replace(/^Viện kiểm sát/u, 'viện kiểm sát')
            .replace(/^VIỆN KIỂM SÁT/u, 'viện kiểm sát');
        }

        const match = raw.match(/(\d{1,2})[/-](\d{1,2})[/-](\d{4})/u);
        if (!match)
          return raw
            .replace(/^Viện kiểm sát/u, 'viện kiểm sát')
            .replace(/^VIỆN KIỂM SÁT/u, 'viện kiểm sát');

        return `ngày ${Number(match[1])} tháng ${Number(match[2])} năm ${match[3]}`;
      };

      anyPayload.agency = anyPayload.agency || {};
